const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let x = [];
let y = [];
let i = 0;
rl.on('line', (line) => {
    if (!n) {
        n = parseInt(line);
    } else {
        let input = line.split(' ');
        x.push(parseInt(input[0]));
        y.push(parseInt(input[1]));
        i++;
        if (i === n) {
            let min = 1e9;
            for (let j = 0; j < n; j++) {
                for (let k = j + 1; k < n; k++) {
                    let d = Math.sqrt((x[j] - x[k]) * (x[j] - x[k]) + (y[j] - y[k]) * (y[j] - y[k]));
                    if (d < min) {
                        min = d;
                    }
                }
            }
            console.log(min);
            rl.close();
        }
    }
});
